215	/// Finds or creates an open upvalue for stack slot `level`.
216	///
217	/// Searches `state.openupval` (sorted descending by StackIdx) for an existing
218	/// open upvalue at exactly `level`. If found, returns it. Otherwise, inserts a
219	/// new one at the correct sorted position and returns it.
220	///
221	/// C: `UpVal *luaF_findupval(lua_State *L, StkId level)`
222	pub(crate) fn find_upval(state: &mut LuaState, level: StackIdx) -> GcRef<UpVal> {
223	    // C: lua_assert(isintwups(L) || L->openupval == NULL);
224	    debug_assert!(
225	        state_in_twups(state) || state.openupval.is_empty(),
226	        "thread must be in twups if it has open upvalues"
227	    );
228	    // C: UpVal **pp = &L->openupval;
229	    //    while ((p = *pp) != NULL && uplevel(p) >= level) {
230	    //      lua_assert(!isdead(G(L), p));
231	    //      if (uplevel(p) == level) return p;  /* found */
232	    //      pp = &p->u.open.next;
233	    //    }
234	    //    return newupval(L, level, pp);
235	    //
236	    // The list is sorted descending. We scan from index 0 (highest) downward.
237	    // When we find an entry with idx < level we've passed the insertion point.
238	    let mut insert_pos = state.openupval.len(); // default: append at end
239	    for (i, uv_ref) in state.openupval.iter().enumerate() {
240	        // C: lua_assert(!isdead(G(L), p)) — GC liveness; no-op in Phase A–C
241	        // macros.tsv: uplevel → extract thread_stack_idx from UpVal::Open
242	        let uv_idx = match &*uv_ref.slot() {
243	            lua_types::UpValState::Open { thread_id: _, idx: thread_stack_idx } => *thread_stack_idx,
244	            lua_types::UpValState::Closed(_) => {
245	                debug_assert!(false, "closed upvalue found in openupval list");
246	                continue;
247	            }
248	        };
249	        if uv_idx.0 >= level.0 {
250	            if uv_idx == level {
251	                // C: if (uplevel(p) == level) return p;
252	                return uv_ref.clone();
253	            }
254	            // uv_idx.0 > level.0: this entry is higher on the stack; keep searching.
255	        } else {
256	            // uv_idx.0 < level.0: correct insertion point reached.
257	            insert_pos = i;
258	            break;
259	        }
260	    }
261	    // C: return newupval(L, level, pp);
262	    new_open_upval(state, level, insert_pos)
263	}
